function updateHUD(): void {
  const endsDisplay = game.mode === 'practice' ? '--' : `${game.currentEnd}/${game.totalEnds}`;
  setText('hud', 'hud-end', endsDisplay);
  setText('hud', 'hud-player-score', String(game.playerScore));
